using System;
using System.Collections.Generic;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

var errors = build.FindChildrenRecursive<Error>();
var failedProjects = new HashSet<string>();

Console.WriteLine("=== BUILD ERRORS ===");
Console.WriteLine();

foreach (var error in errors)
{
    var text = error.ToString();
    Console.WriteLine($"  {text}");
    Console.WriteLine($"  File: {error.File}:{error.LineNumber}");
    Console.WriteLine($"  Project: {error.ProjectFile}");
    Console.WriteLine();

    if (!string.IsNullOrEmpty(error.ProjectFile))
        failedProjects.Add(error.ProjectFile);
}

Console.WriteLine($"=== SUMMARY ===");
Console.WriteLine($"Total errors: {errors.Count}");
Console.WriteLine($"Failed projects:");
foreach (var proj in failedProjects.OrderBy(p => p))
    Console.WriteLine($"  - {proj}");
EOF
